def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def forecast_window_shift(window, index):
        # Simulating a shift in time windows as the day progresses (can customize logic for real data)
        shift = np.sin(index * np.pi / 180) * 5  # Example: sinusoidal shift
        return (window[0] + shift, window[1] + shift)

    best_node = None
    min_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        to_customer_time = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + to_customer_time
        predicted_window = forecast_window_shift(time_windows[i], i)

        if arrival_time < predicted_window[0]:
            wait_time = predicted_window[0] - arrival_time
        elif arrival_time > predicted_window[1]:
            wait_time = (arrival_time - predicted_window[1]) * 10
        else:
            wait_time = 0

        travel_cost = to_customer_time + wait_time

        if travel_cost < min_cost:
            min_cost = travel_cost
            best_node = i

    return best_node

