        if start_window > arrival_time:
            wait_time = (start_window - arrival_time) ** 2  # squaring to heavily penalize early arrival waits
        else:
            wait_time = 0

        if end_window < arrival_time:
            penalty = (arrival_time - end_window) ** 2  # squaring to heavily penalize late arrivals
        else:
            penalty = 0

        # New dynamic adjustment for fleet distribution
        fleet_dist_score = calculate_fleet_distribution_score(customer_pos, all_truck_pos) 

